#include <bits/stdc++.h>
using namespace std;
class TrieNode {
public:
	TrieNode() {
		children[0] = children[1] = nullptr;
		end_of_word = false;
	}
	TrieNode* children[2];
	bool end_of_word;
};
class Trie {
public:
	Trie() : root(new TrieNode()) {}
	void insert(const string& word) {
		TrieNode* root_node = root;
		for (auto c : word) {
			int index = c - 'a';
			if (root_node->children[index] == nullptr) {
				root_node->children[index] = new TrieNode();
			}
			root_node = root_node->children[index];
			root_node->end_of_word = true;
		}
	}
	bool search(const string& word) {
		TrieNode* root_node = root;
		for (auto c : word) {
			int index = c - 'a';
			if (root_node->children[index] == nullptr) {
				return false;
			}
			root_node = root_node->children[index];
		}
		return root_node->end_of_word;
	}
private:
	TrieNode* root;
};
int main() {
	Trie trie;
	string word;
	while (cin >> word) {
		trie.insert(word);
	}
	if (trie.search(word))
		cout << "Yes\n";
	else
		cout << "No\n";
	return 0;
}
